{"path":"/app/hierarchical_model.stan","old_text":"","new_text":"data {
  int<lower=0> N;
  array[N] int<lower=0> y;
  array[N] int<lower=1> n;
}
parameters {
  real<lower=0> alpha;
  real<lower=0> beta;
}
transformed parameters {
  array[N] real<lower=0,upper=1> theta;
  for (i in 1:N)
    theta[i] = alpha / (alpha + beta);
}
model {
  // Prior: p(alpha, beta) proportional to (alpha + beta)^(-5/2)
  target += -2.5 * log(alpha + beta);

  // Likelihood
  for (i in 1:N)
    y[i] ~ binomial(n[i], theta[i]);
}
"}
